void human_igh_imgt_load_config(SimConfig *cfg) {
    sim_config_init(cfg, CHAIN_IGH);

    for (int i = 0; i < v_alleles_count; i++)
        allele_pool_add(&cfg->v_alleles, &v_alleles[i]);

    for (int i = 0; i < d_alleles_count; i++)
        allele_pool_add(&cfg->d_alleles, &d_alleles[i]);

    for (int i = 0; i < j_alleles_count; i++)
        allele_pool_add(&cfg->j_alleles, &j_alleles[i]);

    /* Trim distributions */
    if (v_trim_3_probs_len > 0) {
        cfg->v_trim_3.max_trim = v_trim_3_probs_len;
        cfg->v_trim_3.probs = malloc(v_trim_3_probs_len * sizeof(double));
        memcpy(cfg->v_trim_3.probs, v_trim_3_probs, v_trim_3_probs_len * sizeof(double));
    }
    if (j_trim_5_probs_len > 0) {
        cfg->j_trim_5.max_trim = j_trim_5_probs_len;
        cfg->j_trim_5.probs = malloc(j_trim_5_probs_len * sizeof(double));
        memcpy(cfg->j_trim_5.probs, j_trim_5_probs, j_trim_5_probs_len * sizeof(double));
    }
    if (d_trim_5_probs_len > 0) {
        cfg->d_trim_5.max_trim = d_trim_5_probs_len;
        cfg->d_trim_5.probs = malloc(d_trim_5_probs_len * sizeof(double));
        memcpy(cfg->d_trim_5.probs, d_trim_5_probs, d_trim_5_probs_len * sizeof(double));
    }
    if (d_trim_3_probs_len > 0) {
        cfg->d_trim_3.max_trim = d_trim_3_probs_len;
        cfg->d_trim_3.probs = malloc(d_trim_3_probs_len * sizeof(double));
        memcpy(cfg->d_trim_3.probs, d_trim_3_probs, d_trim_3_probs_len * sizeof(double));
    }

    cfg->np1_length_max = 50;
    cfg->np2_length_max = 50;
}

void human_igh_imgt_load_s5f(S5FModel *model) {
    /* Copy mutability table */
    memcpy(model->mutability, s5f_mutability_data, sizeof(s5f_mutability_data));

    /* Load substitution data */
    for (int i = 0; i < s5f_sub_count; i++) {
        int key = s5f_sub_keys[i];
        s5f_set_substitution(model, key,
                              s5f_sub_bases[i],
                              &s5f_sub_weights[i * 4],
                              s5f_sub_counts[i]);
    }
}
